using LifeOS.Core.FinancialRecords; using LifeOS.Mobile.Core.Money;
namespace LifeOS.Mobile.Views;
public sealed class ManualFinancialReviewPage : ContentPage
{
 public ManualFinancialReviewPage(V11MoneyService service,FinancialDataset data){Title="Manual review";BackgroundColor=MoneyVisuals.Background;var status=new Label{Text="Draft has not been committed.",TextColor=MoneyVisuals.Secondary};var confirm=MoneyVisuals.Action("Review and confirm fictional transaction");confirm.Clicked+=(_,_)=>{try{var draft=new FinancialTransaction("manual-demo","manual-proof-58","acct-operating",TransactionDirection.Income,125m,"NZD",DateOnly.FromDateTime(DateTime.Today),"Fictional reviewed work","cat-work","party-a",FinancialReviewState.PendingReview,[new(FinancialLinkType.Work,"work-demo","Reviewed work")],[]);var result=service.ConfirmManual(draft,data.Transactions);status.Text=$"Confirmed explicitly: {result.Currency} {result.Amount:N2} • {result.ReviewState}";}catch(Exception ex){status.Text=FinancialRecordService.Redact(ex.Message);}};Content=new ScrollView{Content=new VerticalStackLayout{Padding=20,Spacing=14,Children={new Label{Text="Manual financial record",FontSize=30,FontAttributes=FontAttributes.Bold,TextColor=Colors.White},MoneyVisuals.CardView("Review required","Amount NZD 125.00\nCategory Client work\nLinked Work record\nNo provider write"),confirm,status,MoneyVisuals.CardView("Confirmation boundary","Nothing is saved or trusted until the explicit confirmation action succeeds.")}}};}
}
